@namespace sv_23c9cb1752704f0d9c55f5f734fb9493.Components.JobApplication

<nav class="step-indicator mb-4" aria-label="Application progress">
    <div class="d-flex justify-content-between position-relative">
        <div class="step-connector"></div>
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isActive = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = step > CurrentStep && !isCompleted;

            <div class="step-item text-center @(isActive ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                 @onclick="() => OnStepClick(step)"
                 role="@(isCompleted ? "button" : "")"
                 tabindex="@(isCompleted ? 0 : -1)">
                <div class="step-circle mx-auto">
                    @if (isCompleted && !isActive)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <div class="step-label mt-1">@StepNames[i]</div>
            </div>
        }
    </div>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    padding: 0 1rem;
}

.step-indicator .d-flex {
    gap: 0;
}

.step-item {
    flex: 1;
    position: relative;
    z-index: 1;
}

.step-connector {
    position: absolute;
    top: 18px;
    left: 10%;
    right: 10%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.85rem;
    background: #e9ecef;
    color: #adb5bd;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    background: #0d6efd;
    color: #fff;
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.25);
}

.step-item.completed .step-circle {
    background: #198754;
    color: #fff;
}

.step-item.future .step-circle {
    background: #e9ecef;
    color: #adb5bd;
}

.step-label {
    font-size: 0.75rem;
    color: #6c757d;
    white-space: nowrap;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.future .step-label {
    color: #adb5bd;
}

.step-item.completed {
